// // This module selects between two inputs, `input1` and `input2`, based on the value of the `address` input; when `address` is 1, the output `out` reflects the value of `input1`, and when `address` is 0, the output takes the value of `input2`.
module top_module(
	output reg     out,
	input       address,
	input  input1,
	input input2
);always @* begin

		 if (address == 0)
		 	out<=input1;
		else
			out<=input2;

end

endmodule
